-- Mountain of Fire and Miracle Ministry - Complete Database Schema
-- Deploy this on Supabase

-- Create profiles table (for admin staff only)\nCREATE TABLE IF NOT EXISTS profiles (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  email VARCHAR(255) UNIQUE NOT NULL,\n  display_name VARCHAR(255) NOT NULL,\n  role VARCHAR(50) DEFAULT 'staff', -- 'admin' or 'staff'\n  photo_url TEXT,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create services table\nCREATE TABLE IF NOT EXISTS services (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  title VARCHAR(255) NOT NULL,\n  description TEXT NOT NULL,\n  date DATE NOT NULL,\n  time TIME NOT NULL,\n  location VARCHAR(255) NOT NULL,\n  speaker VARCHAR(255),\n  max_attendees INTEGER,\n  current_attendees INTEGER DEFAULT 0,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create service subscribers table\nCREATE TABLE IF NOT EXISTS service_subscribers (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  service_id UUID NOT NULL REFERENCES services(id) ON DELETE CASCADE,\n  email VARCHAR(255) NOT NULL,\n  notification_enabled BOOLEAN DEFAULT TRUE,\n  subscribed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create testimonies table\nCREATE TABLE IF NOT EXISTS testimonies (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  author VARCHAR(255) NOT NULL,\n  title VARCHAR(255) NOT NULL,\n  content TEXT NOT NULL,\n  likes INTEGER DEFAULT 0,\n  status VARCHAR(50) DEFAULT 'pending', -- 'pending', 'approved', 'rejected'\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create events table\nCREATE TABLE IF NOT EXISTS events (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  title VARCHAR(255) NOT NULL,\n  description TEXT NOT NULL,\n  date DATE NOT NULL,\n  time TIME NOT NULL,\n  location VARCHAR(255) NOT NULL,\n  category VARCHAR(50), -- 'conference', 'prayer', 'service', 'fellowship'\n  attendees INTEGER DEFAULT 0,\n  image_url TEXT,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create event registrations table\nCREATE TABLE IF NOT EXISTS event_registrations (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  event_id UUID NOT NULL REFERENCES events(id) ON DELETE CASCADE,\n  email VARCHAR(255) NOT NULL,\n  name VARCHAR(255) NOT NULL,\n  registered_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create donations table\nCREATE TABLE IF NOT EXISTS donations (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  amount DECIMAL(10, 2) NOT NULL,\n  type VARCHAR(50), -- 'general', 'building', 'missions', 'welfare'\n  donor_name VARCHAR(255),\n  donor_email VARCHAR(255),\n  transaction_id VARCHAR(255) UNIQUE,\n  status VARCHAR(50) DEFAULT 'completed', -- 'pending', 'completed', 'failed'\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create contact messages table\nCREATE TABLE IF NOT EXISTS contact_messages (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  name VARCHAR(255) NOT NULL,\n  email VARCHAR(255) NOT NULL,\n  subject VARCHAR(255) NOT NULL,\n  message TEXT NOT NULL,\n  status VARCHAR(50) DEFAULT 'new', -- 'new', 'read', 'replied'\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create announcements table\nCREATE TABLE IF NOT EXISTS announcements (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  title VARCHAR(255) NOT NULL,\n  content TEXT NOT NULL,\n  category VARCHAR(50), -- 'urgent', 'event', 'general'\n  created_by UUID NOT NULL REFERENCES profiles(id),\n  published_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  expires_at TIMESTAMP,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create prayer requests table\nCREATE TABLE IF NOT EXISTS prayer_requests (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  requester_name VARCHAR(255) NOT NULL,\n  requester_email VARCHAR(255),\n  request TEXT NOT NULL,\n  category VARCHAR(50), -- 'personal', 'family', 'health', 'financial', 'other'\n  is_public BOOLEAN DEFAULT FALSE,\n  prayer_count INTEGER DEFAULT 0,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create prayer prayers table (track who prayed)\nCREATE TABLE IF NOT EXISTS prayer_participants (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  prayer_request_id UUID NOT NULL REFERENCES prayer_requests(id) ON DELETE CASCADE,\n  email VARCHAR(255),\n  prayed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create notifications table\nCREATE TABLE IF NOT EXISTS notifications (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  recipient_email VARCHAR(255) NOT NULL,\n  title VARCHAR(255) NOT NULL,\n  message TEXT NOT NULL,\n  type VARCHAR(50), -- 'success', 'error', 'info', 'warning'\n  is_read BOOLEAN DEFAULT FALSE,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create hymns table\nCREATE TABLE IF NOT EXISTS hymns (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  title VARCHAR(255) NOT NULL,\n  lyrics TEXT NOT NULL,\n  category VARCHAR(50), -- 'hymns', 'worship', 'gospel'\n  youtube_url TEXT,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create bible verses table\nCREATE TABLE IF NOT EXISTS bible_verses (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  book VARCHAR(50) NOT NULL,\n  chapter INTEGER NOT NULL,\n  verse INTEGER NOT NULL,\n  text TEXT NOT NULL,\n  translation VARCHAR(50) DEFAULT 'KJV', -- King James Version\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create prayer books table\nCREATE TABLE IF NOT EXISTS prayer_books (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  title VARCHAR(255) NOT NULL,\n  author VARCHAR(255) NOT NULL,\n  description TEXT,\n  content TEXT NOT NULL,\n  category VARCHAR(50), -- 'prayer', 'devotion', 'healing', 'prosperity'\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create activity log table\nCREATE TABLE IF NOT EXISTS activity_logs (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  user_id UUID REFERENCES profiles(id),\n  action VARCHAR(255) NOT NULL,\n  resource_type VARCHAR(50),\n  resource_id VARCHAR(255),\n  ip_address VARCHAR(45),\n  user_agent TEXT,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create indexes for better performance\nCREATE INDEX idx_services_date ON services(date);\nCREATE INDEX idx_services_location ON services(location);\nCREATE INDEX idx_testimonies_status ON testimonies(status);\nCREATE INDEX idx_testimonies_created_at ON testimonies(created_at DESC);\nCREATE INDEX idx_events_date ON events(date);\nCREATE INDEX idx_events_category ON events(category);\nCREATE INDEX idx_donations_created_at ON donations(created_at DESC);\nCREATE INDEX idx_donations_status ON donations(status);\nCREATE INDEX idx_announcements_published_at ON announcements(published_at DESC);\nCREATE INDEX idx_prayer_requests_category ON prayer_requests(category);\nCREATE INDEX idx_prayer_requests_created_at ON prayer_requests(created_at DESC);\nCREATE INDEX idx_notifications_recipient_email ON notifications(recipient_email);\nCREATE INDEX idx_notifications_is_read ON notifications(is_read);\nCREATE INDEX idx_hymns_category ON hymns(category);\nCREATE INDEX idx_prayer_books_category ON prayer_books(category);\nCREATE INDEX idx_activity_logs_user_id ON activity_logs(user_id);\nCREATE INDEX idx_activity_logs_created_at ON activity_logs(created_at DESC);\n\n-- Create views for common queries\nCREATE OR REPLACE VIEW upcoming_services AS\nSELECT * FROM services\nWHERE date >= CURRENT_DATE\nORDER BY date ASC, time ASC;\n\nCREATE OR REPLACE VIEW approved_testimonies AS\nSELECT * FROM testimonies\nWHERE status = 'approved'\nORDER BY created_at DESC;\n\nCREATE OR REPLACE VIEW recent_donations AS\nSELECT * FROM donations\nWHERE status = 'completed'\nORDER BY created_at DESC;\n\nCREATE OR REPLACE VIEW active_announcements AS\nSELECT * FROM announcements\nWHERE expires_at IS NULL OR expires_at > CURRENT_TIMESTAMP\nORDER BY published_at DESC;\n\n-- Create functions for common operations\nCREATE OR REPLACE FUNCTION update_testimony_likes(testimony_id UUID, increment INTEGER DEFAULT 1)\nRETURNS INTEGER AS $$\nDECLARE\n  new_likes INTEGER;\nBEGIN\n  UPDATE testimonies\n  SET likes = likes + increment\n  WHERE id = testimony_id\n  RETURNING likes INTO new_likes;\n  RETURN new_likes;\nEND;\n$$ LANGUAGE plpgsql;\n\nCREATE OR REPLACE FUNCTION update_prayer_count(prayer_id UUID)\nRETURNS INTEGER AS $$\nDECLARE\n  new_count INTEGER;\nBEGIN\n  UPDATE prayer_requests\n  SET prayer_count = prayer_count + 1\n  WHERE id = prayer_id\n  RETURNING prayer_count INTO new_count;\n  RETURN new_count;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Enable RLS (Row Level Security)\nALTER TABLE profiles ENABLE ROW LEVEL SECURITY;\nALTER TABLE services ENABLE ROW LEVEL SECURITY;\nALTER TABLE testimonies ENABLE ROW LEVEL SECURITY;\nALTER TABLE events ENABLE ROW LEVEL SECURITY;\nALTER TABLE donations ENABLE ROW LEVEL SECURITY;\nALTER TABLE contact_messages ENABLE ROW LEVEL SECURITY;\nALTER TABLE announcements ENABLE ROW LEVEL SECURITY;\nALTER TABLE prayer_requests ENABLE ROW LEVEL SECURITY;\nALTER TABLE notifications ENABLE ROW LEVEL SECURITY;\nALTER TABLE activity_logs ENABLE ROW LEVEL SECURITY;\n\n-- Create RLS policies for public access (read-only)\nCREATE POLICY \"Allow public read access to services\"\n  ON services FOR SELECT\n  USING (true);\n\nCREATE POLICY \"Allow public read access to approved testimonies\"\n  ON testimonies FOR SELECT\n  USING (status = 'approved' OR true);\n\nCREATE POLICY \"Allow public read access to events\"\n  ON events FOR SELECT\n  USING (true);\n\nCREATE POLICY \"Allow public read access to hymns\"\n  ON hymns FOR SELECT\n  USING (true);\n\nCREATE POLICY \"Allow public read access to bible verses\"\n  ON bible_verses FOR SELECT\n  USING (true);\n\nCREATE POLICY \"Allow public read access to prayer books\"\n  ON prayer_books FOR SELECT\n  USING (true);\n\nCREATE POLICY \"Allow public read access to announcements\"\n  ON announcements FOR SELECT\n  USING (true);\n\nCREATE POLICY \"Allow anyone to insert contact messages\"\n  ON contact_messages FOR INSERT\n  WITH CHECK (true);\n\nCREATE POLICY \"Allow anyone to insert prayer requests\"\n  ON prayer_requests FOR INSERT\n  WITH CHECK (true);\n\nCREATE POLICY \"Allow anyone to insert testimonies\"\n  ON testimonies FOR INSERT\n  WITH CHECK (true);\n\nCREATE POLICY \"Allow anyone to insert donations\"\n  ON donations FOR INSERT\n  WITH CHECK (true);\n\nCREATE POLICY \"Allow anyone to register for events\"\n  ON event_registrations FOR INSERT\n  WITH CHECK (true);\n\nCREATE POLICY \"Allow anyone to subscribe to services\"\n  ON service_subscribers FOR INSERT\n  WITH CHECK (true);\n\n-- Sample data\nINSERT INTO profiles (email, display_name, role) VALUES\n  ('admin@mfmm.com', 'Pastor John', 'admin'),\n  ('staff@mfmm.com', 'Church Staff', 'staff');\n\nINSERT INTO services (title, description, date, time, location, speaker) VALUES\n  ('Sunday Service', 'Main service of the week with worship and messages', CURRENT_DATE + INTERVAL '7 days', '10:00', 'Main Sanctuary', 'Pastor John'),\n  ('Midweek Service', 'Prayer and Bible study session', CURRENT_DATE + INTERVAL '3 days', '19:00', 'Fellowship Hall', 'Pastor Mary');\n\nINSERT INTO announcements (title, content, category, created_by) VALUES\n  ('Welcome to MFMM', 'Welcome to Mountain of Fire and Miracle Ministry. We are glad to have you here.', 'general', (SELECT id FROM profiles WHERE email = 'admin@mfmm.com' LIMIT 1)),\n  ('New Bible Study', 'Join us for a new Bible study series starting next month.', 'event', (SELECT id FROM profiles WHERE email = 'admin@mfmm.com' LIMIT 1));\n\nINSERT INTO hymns (title, lyrics, category, youtube_url) VALUES\n  ('Amazing Grace', 'Amazing grace, how sweet the sound\\nThat saved a wretch like me...', 'hymns', 'https://www.youtube.com/embed/X6jxDUTzbbE'),\n  ('Great Is Thy Faithfulness', 'Great is thy faithfulness, O God my Father...', 'hymns', 'https://www.youtube.com/embed/xZMN4ZQRJYE');\n\n-- Create functions for automatic timestamps\nCREATE OR REPLACE FUNCTION update_timestamp()\nRETURNS TRIGGER AS $$\nBEGIN\n  NEW.updated_at = CURRENT_TIMESTAMP;\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Apply triggers for automatic timestamp updates\nCREATE TRIGGER update_profiles_timestamp\n  BEFORE UPDATE ON profiles\n  FOR EACH ROW\n  EXECUTE FUNCTION update_timestamp();\n\nCREATE TRIGGER update_services_timestamp\n  BEFORE UPDATE ON services\n  FOR EACH ROW\n  EXECUTE FUNCTION update_timestamp();\n\nCREATE TRIGGER update_testimonies_timestamp\n  BEFORE UPDATE ON testimonies\n  FOR EACH ROW\n  EXECUTE FUNCTION update_timestamp();\n\nCREATE TRIGGER update_events_timestamp\n  BEFORE UPDATE ON events\n  FOR EACH ROW\n  EXECUTE FUNCTION update_timestamp();\n\nCREATE TRIGGER update_donations_timestamp\n  BEFORE UPDATE ON donations\n  FOR EACH ROW\n  EXECUTE FUNCTION update_timestamp();\n\nCREATE TRIGGER update_announcements_timestamp\n  BEFORE UPDATE ON announcements\n  FOR EACH ROW\n  EXECUTE FUNCTION update_timestamp();\n\nCREATE TRIGGER update_prayer_requests_timestamp\n  BEFORE UPDATE ON prayer_requests\n  FOR EACH ROW\n  EXECUTE FUNCTION update_timestamp();\n"